using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // FormatPhoneNumber tests

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.StartsWith(result, "(800)");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        StringAssert.EndsWith(result, "1234");
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.AreEqual("(800) 555-1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    [TestMethod]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.FormatPhoneNumber("123"));
    }

    // BuildGreeting tests

    [TestMethod]
    public void BuildGreeting_DefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.StartsWith(result, "Dear Mr.");
    }

    [TestMethod]
    public void BuildGreeting_DefaultTitle_EndsWithNameAndComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        StringAssert.EndsWith(result, "Smith,");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_StartsWithDearAndTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        StringAssert.StartsWith(result, "Dear Dr.");
    }

    [TestMethod]
    public void BuildGreeting_CustomTitle_ReturnsFullGreeting()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.AreEqual("Dear Dr. Johnson,", result);
    }

    [TestMethod]
    public void BuildGreeting_WhitespaceName_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.BuildGreeting("   "));
    }

    // GenerateSlug tests

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StartsWithFirstWord()
    {
        var result = _formatter.GenerateSlug("  My Great Post!!! ");

        StringAssert.StartsWith(result, "my");
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_EndsWithLastWord()
    {
        var result = _formatter.GenerateSlug("  My Great Post!!! ");

        StringAssert.EndsWith(result, "post");
    }

    [TestMethod]
    public void GenerateSlug_MultipleSpaces_CollapsesToSingleDash()
    {
        var result = _formatter.GenerateSlug("Hello   World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_WhitespaceOnly_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _formatter.GenerateSlug("   "));
    }

    // FormatCurrency tests

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        StringAssert.StartsWith(result, "$");
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(42m);

        StringAssert.EndsWith(result, ".00");
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        StringAssert.StartsWith(result, "€");
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_StartsWithSymbolAndMinus()
    {
        var result = _formatter.FormatCurrency(-5.50m);

        StringAssert.StartsWith(result, "$-");
    }

    [TestMethod]
    public void FormatCurrency_ReturnsCorrectFormat()
    {
        var result = _formatter.FormatCurrency(1234.56m);

        Assert.AreEqual("$1234.56", result);
    }
}

